  "code": "def topological_sort(dependencies):
    # Create an adjacency list representation of the graph
    graph = {task: set() for task in dependencies}
    indegree = {task: 0 for task in dependencies}

    # Build the graph and calculate indegrees
    for task, dependents in dependencies.items():
        for dependent in dependents:
            graph[dependent].add(task)
            indegree[task] += 1

    # Initialize queue with tasks with no dependencies
    queue = [task for task in dependencies if indegree[task] == 0]
    sorted_tasks = []

    while queue:
        task = queue.pop(0)
        sorted_tasks.append(task)
        for dependent in graph[task]:
            indegree[dependent] -= 1
            if indegree[dependent] == 0:
                queue.append(dependent)

    # Check for cycles
    if len(sorted_tasks) != len(dependencies):
        return 'Error: Cycle detected'

    return sorted_tasks",
