    minor1 = int(match_v1.group(2) if len(match_v1.groups()) > 2 else 0)
    patch1 = int(match_v1.group(3) if len(match_v1.groups()) > 3 else 0)

    major2 = int(match_v2.group(1))
    minor2 = int(match_v2.group(2) if len(match_v2.groups()) > 2 else 0)
    patch2 = int(match_v2.group(3) if len(match_v2.groups()) > 3 else 0)

    # Compare major version
    if major1 != major2:
        return (major1 - major2)

    # Compare minor version
    if minor1 != minor2:
