  "approach": "Use a dictionary to store key-value pairs and a doubly linked list to maintain the order of access. When a new item is added, it becomes the most recently used. If the cache reaches its capacity, the least recently used item is evicted.",
  "code": "from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = OrderedDict()

    def get(self, key: int) -> int:
        if key in self.cache:
            # Move the accessed item to the end of the cache
            self.cache.move_to_end(key)
            return self.cache[key]
        else:
            return -1

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            # Update the existing key's value and move it to the end
            self.cache.move_to_end(key)
        else:
            # Add a new item to the cache
            self.cache[key] = value

        # If the cache exceeds capacity, remove the least recently used item
        if len(self.cache) > self.capacity:
            self.cache.popitem(last=False)

# Minimal self-test
if __name__ == '__main__':
    lru_cache = LRUCache(2)
    lru_cache.put(1, 1)
    lru_cache.put(2, 2)
