  "code": "from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        self.cache = OrderedDict()
        self.capacity = capacity
        self.current_size = 0

    def get(self, key: int) -> int:
        if key in self.cache:
            # Move the accessed item to the end for LRU behavior
            value = self.cache.pop(key)
            self.cache[key] = value
            return value
        else:
            return -1

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            # Update the existing item and move it to the end for LRU behavior
            del self.cache[key]
        elif self.current_size >= self.capacity:
            # Remove the least recently used item (first item in OrderedDict)
            removed_key = next(iter(self.cache))
            del self.cache[removed_key]
            self.current_size -= 1
        # Add or update the new item and increase size
        self.cache[key] = value
        self.current_size += 1

    def __str__(self):
        return str(dict(self.cache))"
