    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]) + 1

    # Reconstruct the optimal edit sequence
    i, j = m, n
    edits = []
    while i > 0 and j > 0:
        if s1[i - 1] == s2[j - 1]:
            edits.append(('equal', s1[i - 1]))
            i -= 1
            j -= 1
        elif dp[i - 1][j] < dp[i][j - 1] and dp[i - 1][j] < dp[i - 1][j - 1]:
