    # Initialize a memo table to store results of subproblems
    memo = [[-1] * (len(str2) + 1) for _ in range(len(str1) + 1)]

    def edit_distance_recursive(i, j):
        if i == len(str1):
            return len(str2) - j
        elif j == len(str2):
            return len(str1) - i
        elif memo[i][j] != -1:
