  "task_summary": "Detect cycles in a wait-for graph represented as an adjacency dictionary",
  "approach": "Use Depth-First Search (DFS) to traverse the graph and detect cycles.",
  "code": "import collections

def find_cycle(graph):
    visited = set()
    stack = []

    def dfs(node, parent):
        if node in visited:
            return True
        visited.add(node)
        stack.append(node)

        for neighbor in graph[node]:
            if neighbor == parent:
                continue
            if dfs(neighbor, node):
                return True

        stack.pop()
        return False

    for node in graph:
        if dfs(node, None):
            cycle = [node]
            current = node
            while stack and stack[-1] != current:
                cycle.append(stack.pop())
            cycle.reverse()
            return cycle

    return None",
