  "code": "import datetime

def do_overlap(range1, range2):
    # Parse the input strings into datetime objects
    try:
        start1 = datetime.datetime.strptime(range1[0], '%Y-%m-%d %H:%M:%S%z') if len(range1) > 1 else None
        end1 = datetime.datetime.strptime(range1[1], '%Y-%m-%d %H:%M:%S%z') if len(range1) > 2 else None
        start2 = datetime.datetime.strptime(range2[0], '%Y-%m-%d %H:%M:%S%z') if len(range2) > 1 else None
        end2 = datetime.datetime.strptime(range2[1], '%Y-%m-%d %H:%M:%S%z') if len(range2) > 2 else None
    except ValueError:
        return False

    # Handle open-ended ranges by setting them to the maximum possible values for their respective types
    if start1 is None:
        start1 = datetime.datetime.max
    if end1 is None:
        end1 = datetime.datetime.min
    if start2 is None:
        start2 = datetime.datetime.max
    if end2 is None:
        end2 = datetime.datetime.min

    # Check for overlap
    return not (end1 < start2 or end2 < start1)
",
