def check_date_overlap(range1_start, range1_end, range2_start, range2_end):
    # Parse string inputs to datetime
    from datetime import datetime, timezone

    def parse_datetime(s):
        if s == 'None':
            return None
        else:
            return datetime.fromisoformat(s)

    start1 = parse_datetime(range1_start)
    end1 = parse_datetime(range1_end)
    start2 = parse_datetime(range2_start)
    end2 = parse_datetime(range2_end)

    # Check for overlap considering open-ended ranges and timezone-awareness
    if (start1 is not None and end1 is not None) and (start2 is not None and end2 is not None):
        return start1 <= end2 and start2 <= end1
    elif start1 is not None and end1 is None:
        return start1 <= end2
    elif start2 is not None and end2 is None:
        return start2 <= end1
    else:
        return False
```
