        'missing_attendees': set(),
        'suspicious_duration': []
    }

    # Dictionary to track events by start time and attendees
    event_dict = {}
    for event in events:
        if event['start'] not in event_dict:
            event_dict[event['start']] = {
                'events': [],
                'attendees': set(event['attendees'])
            }
        else:
            event_dict[event['start']]['events'].append(event)

    for start_time, data in event_dict.items():
        events_at_start = data['events']
        attendees = data['attendees']

        # Check for overlaps with other events at the same time
        for i in range(len(events_at_start)):
            for j in range(i + 1, len(events_at_start)):
                if is_overlap(events_at_start[i], events_at_start[j]):
                    conflicts['overlap'].append((events_at_start[i]['event_id'], events_at_start[j]['event_id']))

