                    try:
                        timestamp_str, component, error_message = line.strip().split(' ', 2)
                        timestamp = datetime.strptime(timestamp_str, '%Y-%m-%d %H:%M:%S.%f')

                        errors_by_component[component].append((timestamp, error_message))
                    except ValueError:
                        continue

